export function getCardAttacks(cardId: string, collectionId: string): [SkillDefinition, SkillDefinition, SkillDefinition] {
    if (CARD_ATTACKS[cardId]) {
        return CARD_ATTACKS[cardId]
    }
    // Fallbacks per collection
    if (collectionId === "valorant") return [{ name: "Tir Précis", cost: 0 }, { name: "Compétence Tactique", cost: 4 }, { name: "Ultime Dévastateur", cost: 8 }]
    if (collectionId === "lol") return [{ name: "Coup de Base", cost: 0 }, { name: "Compétence", cost: 3 }, { name: "Capacité Ultime", cost: 7 }]
    if (collectionId === "cars") return [{ name: "Coup de Pare-chocs", cost: 0 }, { name: "Dérapage Turbo", cost: 3 }, { name: "Vitesse Max", cost: 7 }]
    if (collectionId === "cyberpunk") return [{ name: "Piratage Rapide", cost: 0 }, { name: "Surcharge Cybernétique", cost: 4 }, { name: "Cyberpsychose", cost: 8 }]
    if (collectionId === "breaking_bad") return [{ name: "Jet d'Acide", cost: 0 }, { name: "Tir à vue", cost: 3 }, { name: "Explosion Chimique", cost: 7 }]
    if (collectionId === "stranger_things") return [{ name: "Coup de Batte", cost: 0 }, { name: "Fuite Tactique", cost: 3 }, { name: "Pouvoir Télékinétique", cost: 8 }]
    if (collectionId === "porn_story") return [{ name: "Charme Fatal", cost: 0 }, { name: "Séduction", cost: 3 }, { name: "Endurance Max", cost: 8 }]
    if (collectionId === "f1") return [{ name: "Aspiration", cost: 0 }, { name: "Tour de Qualif", cost: 3 }, { name: "Dépassement DRS", cost: 7 }]
    if (collectionId === "cinema") return [{ name: "Coup de Théâtre", cost: 0 }, { name: "Scène d'Action", cost: 4 }, { name: "Blockbuster", cost: 8 }]
    if (collectionId === "politics") return [{ name: "Débat Animé", cost: 0 }, { name: "Décret Loi", cost: 4 }, { name: "Loi Martiale", cost: 8 }]
    if (collectionId === "fortune") return [{ name: "Billet Moteur", cost: 0 }, { name: "Investissement", cost: 3 }, { name: "Rachat Hostile", cost: 8 }]
    if (collectionId === "nageurs") return [{ name: "Onde de Choc", cost: 0 }, { name: "Virage Culbute", cost: 3 }, { name: "Tsunami", cost: 8 }]
    if (collectionId === "artistes") return [{ name: "Fausse Note", cost: 0 }, { name: "Solo de Guitare", cost: 4 }, { name: "Concert Somptueux", cost: 8 }]
    if (collectionId === "crime") return [{ name: "Coup Bas", cost: 0 }, { name: "Menace Fausse", cost: 3 }, { name: "Évasion Spectaculaire", cost: 8 }]

    // Global Fallback
    return [
        { name: "Attaque Rapide", cost: 0 },
        { name: "Coup Spécial", cost: 4 },
        { name: "Surcharge Ultime", cost: 8 }
    ]
}
